def _auth_reject():
    """JSON 401/403 for /api/* (so client-side JS doesn't get an HTML
    redirect that masquerades as a session timeout); login redirect for pages."""
    if request.path.startswith("/api/"):
        if not session.get("role"):
            return jsonify({"ok": False, "error": "Not authenticated"}), 401
        return jsonify({"ok": False, "error": "Forbidden"}), 403
    return redirect(url_for("login_page", next=request.path))


def require_role(*roles):
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*args, **kwargs):
            if session.get("role") not in roles:
                return _auth_reject()
            return f(*args, **kwargs)
        return wrapper
    return decorator


# Operational endpoints — production managers can access, plus owner.
# Owner-only stuff (delete, password resets, manager management, system config)
# keeps using @require_role("owner") explicitly.
def require_operator(f):
    """Allow owner, production_manager, cfo, OR estimator — anyone who can see
    operational data. Finance numbers stay gated separately by require_finance."""
    @functools.wraps(f)
    def wrapper(*args, **kwargs):
        if session.get("role") not in ("owner", "production_manager", "cfo", "estimator"):
            return _auth_reject()
        return f(*args, **kwargs)
    return wrapper


def require_finance(f):
    """Finance access — owner OR cfo only. Production managers do NOT see
    cost-side numbers, profit, margin, or receipts."""
    @functools.wraps(f)
    def wrapper(*args, **kwargs):
        if session.get("role") not in ("owner", "cfo"):
            return jsonify({"ok": False, "error": "Finance access required."}), 403
        return f(*args, **kwargs)
    return wrapper

def require_employee(f):
    """Allow the check-in flow for either:
      - an employee session (set via /employee-login), OR
      - any logged-in operator (owner / production_manager / cfo) — so
        they can submit a check-in under their own name when they're on site.
    Otherwise redirect to the employee login screen."""
    @functools.wraps(f)
    def wrapper(*args, **kwargs):
        if not session.get("employee_name") and session.get("role") not in ("owner", "production_manager", "cfo"):
            return redirect(url_for("employee_login_page", next=request.path))
        return f(*args, **kwargs)
    return wrapper


def require_api_key(f):
    """M2M auth decorator.  Accepts key via X-Lumia-Key header OR ?api_key= query param.
    Also passes if the caller has an active owner/manager session (browser use)."""
    @functools.wraps(f)
    def wrapper(*args, **kwargs):
        if session.get("role") in ("owner", "manager"):
            return f(*args, **kwargs)
        provided = (
            request.headers.get("X-Lumia-Key")
            or request.args.get("api_key")
            or (request.get_json(silent=True) or {}).get("api_key")
        )
        if not LUMIA_API_KEY:
            # Key not configured — reject to prevent accidental open access
            return jsonify({"ok": False, "error": "LUMIA_API_KEY not configured on server."}), 403
        if not provided or provided != LUMIA_API_KEY:
            return jsonify({"ok": False, "error": "Invalid or missing API key."}), 401
        return f(*args, **kwargs)
    return wrapper


