@app.route("/m/<token>")
def dm_magic_link(token):
    """Tokenized thread page from an SMS notification. Records the open time."""
    if not supabase_client:
        return "Messaging is not available right now.", 503
    try:
        rows = supabase_client.table("dm_notifications").select("*").eq("token", token).limit(1).execute().data or []
    except Exception:
        rows = []
    if not rows:
        return ("<div style='font-family:sans-serif;padding:40px;text-align:center;color:#1F3864'>"
                "<h2>Link expired</h2><p>This message link is no longer valid.</p></div>"), 404
    note = rows[0]
    if not note.get("opened_at"):
        try:
            supabase_client.table("dm_notifications").update(
                {"opened_at": datetime.utcnow().isoformat()}).eq("token", token).execute()
            print(f"[DM] read receipt — {note.get('recipient_name')} opened token {token[:6]}…")
        except Exception:
            pass
    viewer       = note.get("recipient_name")
    viewer_role  = note.get("recipient_role")
    employee     = note.get("employee_name")
    manager      = note.get("manager_name")
    viewer_lang  = _dm_emp_language(viewer)
    # Who's on the other side of the header?
    if viewer_role == "employee":
        other_name, other_title = manager, DM_ROLE_TITLE.get(note.get("recipient_role"), "")
        mr = _dm_role_for(manager)
        other_title = mr[2] if mr else "Management"
    else:
        other_name, other_title = employee, "Crew"
    return render_template_string(
        DM_THREAD_HTML, token=token, viewer=viewer, viewer_lang=viewer_lang,
        viewer_title=DM_ROLE_TITLE.get(viewer_role, "Crew"),
        other_name=other_name, other_title=other_title)


@app.route("/api/dm/thread")
def api_dm_thread():
    """Messages for a tokenized thread (magic-link auth)."""
    if not supabase_client:
        return jsonify({"ok": True, "messages": []})
    token = request.args.get("token") or ""
    try:
        since = int(request.args.get("since") or 0)
    except (TypeError, ValueError):
        since = 0
    rows = supabase_client.table("dm_notifications").select("*").eq("token", token).limit(1).execute().data or []
    if not rows:
        return jsonify({"ok": False, "error": "Invalid link"}), 404
    note = rows[0]
    employee, manager, vrole = note.get("employee_name"), note.get("manager_name"), note.get("recipient_role")
    q = supabase_client.table("dm_messages").select("*") \
        .eq("employee_name", employee).eq("manager_name", manager)
    if since > 0:
        q = q.gt("id", since)
    msgs = q.order("id", desc=False).limit(300).execute().data or []
    return jsonify({"ok": True, "messages": _dm_render_messages_for(vrole, msgs)})


@app.route("/api/dm/reply", methods=["POST"])
def api_dm_reply():
    """Reply within a tokenized thread (magic-link auth)."""
    if not supabase_client:
        return jsonify({"ok": False, "error": "unavailable"}), 503
    d = request.get_json(silent=True) or {}
    token = d.get("token") or ""
    audio_url = d.get("audio_url") or None
    body = (d.get("body") or "").strip() or ("🎤 Voice message" if audio_url else "")
    if not body:
        return jsonify({"ok": False, "error": "Empty message"}), 400
    rows = supabase_client.table("dm_notifications").select("*").eq("token", token).limit(1).execute().data or []
    if not rows:
        return jsonify({"ok": False, "error": "Invalid link"}), 404
    note = rows[0]
    sender = note.get("recipient_name")
    msg = _dm_post_message(note.get("employee_name"), note.get("manager_name"), sender, body,
                           src_lang=(d.get("lang") or None), audio_url=audio_url)
    return jsonify({"ok": bool(msg)})


@app.route("/messages")
@require_employee
def dm_hub_page():
    """Logged-in messaging hub — adapts to crew / manager / president."""
    viewer = _dm_session_name()
    if not viewer:
        return redirect(url_for("employee_login_page", next="/messages"))
    role = _dm_role_for(viewer)
    viewer_role = role[1] if role else "employee"
    return render_template_string(
        DM_HUB_HTML, viewer=viewer, viewer_role=viewer_role,
        viewer_lang=_dm_emp_language(viewer),
        is_president=(viewer_role == "president"))


@app.route("/api/dm/threads")
@require_employee
def api_dm_threads():
    """Thread list for the logged-in viewer."""
    if not supabase_client:
        return jsonify({"ok": True, "threads": []})
    viewer = _dm_session_name()
    vinfo = _dm_role_for(viewer)
    vrole = vinfo[1] if vinfo else "employee"

    # Pull all employees (the "guys") = everyone not on the management roster
    emp_rows = supabase_client.table("employees").select("name").execute().data or []
    all_emps = [e.get("name") for e in emp_rows if e.get("name") and not _dm_is_manager(e.get("name"))]

    # Determine which (employee, manager) pairs this viewer may see
    pairs = []
    if vrole == "president":
        for mgr_canon, mrole, mtitle in DM_MANAGERS:
            for emp in all_emps:
                pairs.append((emp, mgr_canon, mtitle))
    elif vrole in ("vp_ops", "cfo"):
        mgr_canon = vinfo[0]
        for emp in all_emps:
            pairs.append((emp, mgr_canon, vinfo[2]))
    else:
        # a crew member — their 3 manager threads
        for mgr_canon, mrole, mtitle in DM_MANAGERS:
            pairs.append((viewer, mgr_canon, mtitle))

    # Latest message + read-receipt per pair
    threads = []
    for emp, mgr, mtitle in pairs:
        last_rows = supabase_client.table("dm_messages").select("*") \
            .eq("employee_name", emp).eq("manager_name", mgr) \
            .order("id", desc=True).limit(1).execute().data or []
        if not last_rows and not (vrole in ("president", "vp_ops", "cfo")):
            # crew: still show empty manager threads so they can start one
            pass
        last = last_rows[0] if last_rows else None
        preview = ""
        last_at = None
        if last:
            preview = (last.get("body_emp") if vrole == "employee" else last.get("body_en")) or last.get("body") or ""
            last_at = last.get("created_at")
        # Read receipt: did the OTHER side open the most recent notification?
        last_opened = None
        awaiting = False
        if last:
            notif = supabase_client.table("dm_notifications").select("opened_at,recipient_name") \
                .eq("employee_name", emp).eq("manager_name", mgr) \
                .order("id", desc=True).limit(3).execute().data or []
            for n in notif:
                if n.get("recipient_name") != last.get("sender_name"):
                    if n.get("opened_at"):
                        last_opened = n.get("opened_at")
                    else:
                        awaiting = True
                    break
        # Title: who the viewer is talking to
        if vrole in ("president", "vp_ops", "cfo"):
            title = emp
            subtitle = (f"with {mtitle}" if vrole == "president" else "Crew")
        else:
            title = mtitle
            subtitle = mgr
        threads.append({
            "employee_name": emp, "manager_name": mgr,
            "title": title, "subtitle": subtitle,
            "preview": preview[:80], "last_at": last_at,
            "last_opened": last_opened, "awaiting_open": awaiting,
            "_sort": last_at or "",
        })
    # Sort: threads with activity first (newest), empty ones after
    threads.sort(key=lambda t: t["_sort"], reverse=True)
    for t in threads:
        t.pop("_sort", None)
    return jsonify({"ok": True, "threads": threads})


@app.route("/api/dm/messages")
@require_employee
def api_dm_messages():
    """Messages in a thread for a logged-in viewer (session auth)."""
    if not supabase_client:
        return jsonify({"ok": True, "messages": []})
    viewer = _dm_session_name()
    employee = request.args.get("employee") or ""
    manager  = request.args.get("manager") or ""
    if not _dm_can_view(viewer, employee, manager):
        return jsonify({"ok": False, "error": "Not authorized for this thread"}), 403
    try:
        since = int(request.args.get("since") or 0)
    except (TypeError, ValueError):
        since = 0
    vinfo = _dm_role_for(viewer)
    vrole = vinfo[1] if vinfo else "employee"
    q = supabase_client.table("dm_messages").select("*") \
        .eq("employee_name", employee).eq("manager_name", manager)
    if since > 0:
        q = q.gt("id", since)
    msgs = q.order("id", desc=False).limit(300).execute().data or []
    return jsonify({"ok": True, "messages": _dm_render_messages_for(vrole, msgs)})


@app.route("/api/dm/send", methods=["POST"])
@require_employee
def api_dm_send():
    """Send a message in a thread as the logged-in viewer."""
    if not supabase_client:
        return jsonify({"ok": False, "error": "unavailable"}), 503
    viewer = _dm_session_name()
    d = request.get_json(silent=True) or {}
    employee = (d.get("employee") or "").strip()
    manager  = (d.get("manager") or "").strip()
    audio_url = d.get("audio_url") or None
    body     = (d.get("body") or "").strip() or ("🎤 Voice message" if audio_url else "")
    if not (employee and manager and body):
        return jsonify({"ok": False, "error": "Missing fields"}), 400
    if not _dm_can_view(viewer, employee, manager):
        return jsonify({"ok": False, "error": "Not authorized for this thread"}), 403
    # The sender is the viewer (could be the employee, the thread's manager, or the president interjecting)
    msg = _dm_post_message(employee, manager, viewer, body,
                           src_lang=(d.get("lang") or None), audio_url=audio_url)
    return jsonify({"ok": bool(msg)})


# ===========================================================================
# GROUP ROOMS — owner/manager-created conversations with any participants
#   The owner picks a person to text one-on-one, then can ADD anyone else to
#   the conversation. Everyone in the room gets the SMS magic-link + read
#   receipts; each person reads in their own language (managers read English).
# ===========================================================================

def _dm_is_staff_session() -> bool:
    """True if the logged-in person may create/manage rooms (owner or a manager)."""
    if session.get("role") in ("owner", "production_manager", "cfo"):
        return True
    return _dm_is_manager(_dm_session_name())


def _dm_read_lang(name: str) -> str:
    """Managers read English; crew read their own language."""
    return "en" if _dm_is_manager(name) else (_dm_emp_language(name) or "en")


def _dm_room_members(room_id) -> list:
    try:
        return supabase_client.table("dm_room_members").select("*") \
            .eq("room_id", room_id).order("id").execute().data or []
    except Exception:
        return []


def _dm_room_member_names(room_id) -> list:
    return [m.get("member_name") for m in _dm_room_members(room_id)]


def _dm_room_can_access(viewer: str, room_id) -> bool:
    if _dm_is_president(viewer) or session.get("role") == "owner":
        return True
    names = [n.strip().lower() for n in _dm_room_member_names(room_id)]
    return (viewer or "").strip().lower() in names


def _dm_room_title(room_id, members=None, viewer=None) -> str:
    members = members if members is not None else _dm_room_members(room_id)
    names = [m.get("member_name") for m in members]
    # Drop the viewer from the displayed title
    if viewer:
        names = [n for n in names if (n or "").strip().lower() != viewer.strip().lower()]
    if not names:
        return "Conversation"
    if len(names) <= 3:
        return ", ".join(names)
    return f"{names[0]}, {names[1]} +{len(names)-2}"


def _dm_room_add_member(room_id, member_name: str, added_by: str) -> bool:
    member_name = (member_name or "").strip()
    if not member_name:
        return False
    info = _dm_role_for(member_name)
    role = info[1] if info else "employee"
    if info:
        member_name = info[0]
    try:
        supabase_client.table("dm_room_members").upsert({
            "room_id":     room_id,
            "member_name": member_name,
            "member_role": role,
            "added_by":    added_by,
        }, on_conflict="room_id,member_name").execute()
        return True
    except Exception as exc:
        print(f"[Room] add member failed: {exc}")
        return False


def _dm_room_post(room_id, sender_name: str, body: str, src_lang: str = None,
                  audio_url: str = None) -> dict:
    """Post a message to a room. Pre-translates into every language present
    among the members, then notifies all members (except the sender)."""
    if not supabase_client:
        return None
    sinfo = _dm_role_for(sender_name)
    sender_role = sinfo[1] if sinfo else "employee"
    if sinfo:
        sender_name = sinfo[0]
    body = (body or "").strip()
    if not body:
        return None
    if not src_lang:
        src_lang = "en" if sender_role != "employee" else (_dm_emp_language(sender_name) or "en")

    members = _dm_room_members(room_id)
    langs = {"en"}
    for m in members:
        langs.add(_dm_read_lang(m.get("member_name")))
    translations = {}
    for lg in langs:
        translations[lg] = body if lg == src_lang else _dm_translate(body, lg)

    try:
        ins = supabase_client.table("dm_room_messages").insert({
            "room_id":      room_id,
            "sender_name":  sender_name,
            "sender_role":  sender_role,
            "body":         body[:2000],
            "lang":         src_lang,
            "translations": translations,
            "audio_url":    audio_url or None,
        }).execute().data
    except Exception as exc:
        print(f"[Room] message insert failed: {exc}")
        return None
    msg = ins[0] if ins else None
    if not msg:
        return None
    try:
        supabase_client.table("dm_rooms").update(
            {"last_message_at": datetime.utcnow().isoformat()}).eq("id", room_id).execute()
    except Exception:
        pass
    # Background the SMS fan-out so the sender's request returns instantly
    threading.Thread(target=_dm_room_notify,
                     args=(room_id, msg, sender_name, members), daemon=True).start()
    return msg


def _dm_room_notify(room_id, msg, sender_name, members=None):
    members = members if members is not None else _dm_room_members(room_id)
    title = _dm_room_title(room_id, members)
    for m in members:
        nm = m.get("member_name")
        if not nm or nm.strip().lower() == (sender_name or "").strip().lower():
            continue
        token = _dm_secrets.token_urlsafe(16)
        try:
            supabase_client.table("dm_room_notifications").insert({
                "token":          token,
                "room_id":        room_id,
                "message_id":     msg.get("id"),
                "recipient_name": nm,
                "recipient_role": m.get("member_role") or "employee",
            }).execute()
        except Exception as exc:
            print(f"[Room notify] token insert failed for {nm}: {exc}")
            continue
        phone = _dm_emp_field(nm, "phone", "")
        if not phone:
            print(f"[Room notify] {nm}: no phone — web only")
            continue
        rlang = _dm_read_lang(nm)
        preview = (msg.get("translations") or {}).get(rlang) or msg.get("body") or ""
        preview = preview.strip().replace("\n", " ")
        if len(preview) > 90:
            preview = preview[:90] + "…"
        link = f"{DM_BASE_URL}/rm/{token}"
        if rlang == "ar":
            sms_body = f"رسالة جديدة من {sender_name}:\n«{preview}»\nللرد اضغط هنا: {link}"
        elif rlang == "fr":
            sms_body = f"Nouveau message de {sender_name} :\n«{preview}»\nRépondre : {link}"
        else:
            sms_body = f"New message from {sender_name}:\n\"{preview}\"\nReply here: {link}"
        ok, detail = _send_sms(phone, sms_body, category="dm_room")
        if not ok:
            print(f"[Room notify] SMS to {nm} failed: {detail}")


def _dm_room_render(viewer_name: str, rows: list) -> list:
    read_lang = _dm_read_lang(viewer_name)
    out = []
    for r in rows:
        tr = r.get("translations") or {}
        text = tr.get(read_lang) or r.get("body") or ""
        out.append({
            "id":          r.get("id"),
            "sender_name": r.get("sender_name"),
            "sender_role": r.get("sender_role"),
            "role_title":  DM_ROLE_TITLE.get(r.get("sender_role"), ""),
            "text":        text,
            "translated":  text != (r.get("body") or ""),
            "audio_url":   r.get("audio_url"),
            "created_at":  r.get("created_at"),
        })
    return out


def _dm_get_or_create_crew_room(employee_name: str):
    """Find (or create) the single fixed chat for a crew member that always
    contains the President + VP Ops. One per employee, keyed by crew_member."""
    if not supabase_client or not employee_name:
        return None
    try:
        rows = supabase_client.table("dm_rooms").select("id") \
            .eq("crew_member", employee_name).limit(1).execute().data or []
    except Exception as exc:
        print(f"[Crew room] lookup failed: {exc}")
        rows = []
    if rows:
        rid = rows[0]["id"]
    else:
        try:
            ins = supabase_client.table("dm_rooms").insert({
                "created_by":      "system",
                "crew_member":     employee_name,
                "last_message_at": datetime.utcnow().isoformat(),
            }).execute().data
            rid = ins[0]["id"]
        except Exception as exc:
            print(f"[Crew room] create failed: {exc}")
            return None
    # Ensure the three fixed members are present
    _dm_room_add_member(rid, employee_name, "system")
    for m in DM_CREW_ROOM_MEMBERS:
        _dm_room_add_member(rid, m, "system")
    return rid


