        f'<div style="text-align:center;margin:28px 0;">'
        f'<a href="{url}" style="display:inline-block;background:#2563eb;color:#fff;text-decoration:none;'
        f'font-weight:600;padding:14px 28px;border-radius:8px;font-size:15px;">'
