def _send_attention_digest():
    """7 AM Winnipeg time. Run the same scan as /api/attention and email the
    items to Ahmad. Skip silently if nothing is flagged."""
    if not supabase_client or not OWNER_EMAIL:
        return
    today = date.today()
    items: list[dict] = []
    # 1. Tenders closing within 3 days
    try:
        rows = supabase_client.table("tenders").select("*") \
            .gte("close_date", today.isoformat()) \
            .lte("close_date", (today + timedelta(days=3)).isoformat()) \
            .eq("status", "open").execute().data or []
        for t in rows:
            d_left = (date.fromisoformat(t["close_date"]) - today).days
            items.append({"icon":"📅","severity":"high" if d_left <= 1 else "med",
                "title": f"Tender closes in {d_left} day(s): {t.get('name')}",
                "detail": f"{t.get('client') or 'Unknown client'} · closes {t['close_date']}"})
    except Exception: pass
    # 2. Idle jobs
    try:
        jobs = supabase_client.table("jobs").select("id,client_name,site_address,status,start_date") \
            .in_("status", WORKING_JOB_STATUSES).execute().data or []
        checkins = supabase_client.table("checkins").select("site_address,entry_date") \
            .order("entry_date", desc=True).limit(200).execute().data or []
        latest_by_site: dict[str, str] = {}
        for c in checkins:
            site = (c.get("site_address") or "").lower().strip()
            if site and site not in latest_by_site:
                latest_by_site[site] = c.get("entry_date") or ""
        for j in jobs:
            site = (j.get("site_address") or "").lower().strip()
            latest = latest_by_site.get(site, "")
            if latest:
                try:
                    gap = (today - date.fromisoformat(latest)).days
                    if gap >= 4:
                        items.append({"icon":"⏱","severity":"med",
                            "title": f"{gap} days since last check-in: {j.get('site_address')}",
                            "detail": f"{j.get('client_name')} · last check-in {latest}."})
                except Exception: pass
    except Exception: pass
    # 3. Drafts
    try:
        rows = supabase_client.table("quotes").select("id,client_name,project_name,status,created_at") \
            .eq("status", "draft") \
            .lte("created_at", (datetime.utcnow() - timedelta(days=3)).isoformat()) \
            .execute().data or []
        for q in rows[:5]:
            items.append({"icon":"📝","kind":"quote","severity":"low",
                "title": f"Draft quote sitting: {q.get('project_name') or q.get('client_name')}",
                "detail": "Drafted over 3 days ago — send it or archive."})
    except Exception: pass
    # (Concern-type employee notes intentionally excluded — they're already
    #  visible on the employee page and were just adding noise to the digest.)

    if not items:
        print("[Attention Digest] Nothing flagged — skipping email")
        return

    # Build email
    sev_rank = {"high":0,"med":1,"low":2}
    items.sort(key=lambda i: sev_rank.get(i.get("severity","low"), 2))
    items = items[:15]
    lines = ["Hi Ahmad,", "", "Good morning. Here's what needs attention today:", ""]
    for it in items:
        lines.append(f"  {it['icon']}  {it['title']}")
        if it.get("detail"):
            lines.append(f"       {it['detail']}")
        lines.append("")
    lines.append("Open the dashboard to act on any of these.")
    lines.append("")
    lines.append("— Lumia")
    body = "\n".join(lines)
    subject = f"☀ Your Lumia digest — {today.strftime('%A %B %-d')}"

    try:
        import httpx as _httpx
        resend_key = os.getenv("RESEND_API_KEY", "")
        if not resend_key: return
        r = _httpx.post(
            "https://api.resend.com/emails",
            headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
            json={"from":"Lumia <noreply@ashrah.ai>","to":[OWNER_EMAIL],
                  "subject": subject, "text": body},
            timeout=15,
        )
        if r.status_code in (200, 201):
            print(f"[Attention Digest] Sent — {len(items)} item(s)")
            try:
                _log_outbox(category="owner_notice", to=[OWNER_EMAIL],
                            subject=subject, body_text=body,
                            related_kind="digest", related_id=today.isoformat())
            except Exception: pass
        else:
            print(f"[Attention Digest] Send failed: {r.status_code} {r.text[:200]}")
    except Exception as exc:
        print(f"[Attention Digest] Error: {exc}")


def _send_tender_reminders():
    """Daily check: send a reminder for any tender closing in exactly 2 days
    (and not yet notified). Owner gets the email."""
    if not supabase_client or not OWNER_EMAIL:
        return
    try:
        from datetime import date as _date, timedelta as _td
        target = (_date.today() + _td(days=2)).isoformat()
        rows = supabase_client.table("tenders").select("*") \
            .eq("close_date", target) \
            .eq("status", "open") \
            .eq("notified_2d", False) \
            .execute().data or []
        if not rows:
            return
        import httpx as _httpx
        resend_key = os.getenv("RESEND_API_KEY", "")
        if not resend_key:
            print("[Tenders] No RESEND_API_KEY — skipping reminder")
            return
        for t in rows:
            subject = f"⏰ Tender closing in 2 days — {t['name']}"
            body = (
                f"Hi Ahmad,\n\n"
                f"This is a reminder that the following tender closes in 2 days:\n\n"
                f"Tender:  {t['name']}\n"
                f"Client:  {t.get('client') or '—'}\n"
                f"Close:   {t['close_date']}\n"
                f"Status:  {t.get('status') or 'open'}\n"
                f"{('Notes:   ' + t['notes'] + chr(10)) if t.get('notes') else ''}"
                f"\nMake sure your submission is ready.\n\n"
                f"— Lumia"
            )
            try:
                resp = _httpx.post(
                    "https://api.resend.com/emails",
                    headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
                    json={"from":"Lumia <noreply@ashrah.ai>","to":[OWNER_EMAIL],"subject":subject,"text":body},
                    timeout=15,
                )
                if resp.status_code in (200, 201):
                    supabase_client.table("tenders").update({"notified_2d": True}).eq("id", t["id"]).execute()
                    print(f"[Tenders] Reminder sent for '{t['name']}' (closes {t['close_date']})")
                    try:
                        _log_outbox(category="tender_alert", to=[OWNER_EMAIL],
                                    subject=subject, body_text=body,
                                    related_kind="tender", related_id=str(t.get("id") or ""))
                    except Exception: pass
                else:
                    print(f"[Tenders] Reminder failed: {resp.status_code} {resp.text[:200]}")
                    try:
                        _log_outbox(category="tender_alert", to=[OWNER_EMAIL],
                                    subject=subject, body_text=body,
                                    related_kind="tender", related_id=str(t.get("id") or ""),
                                    status="failed", error=f"HTTP {resp.status_code}: {resp.text[:200]}")
                    except Exception: pass
            except Exception as exc:
                print(f"[Tenders] Send error: {exc}")
    except Exception as exc:
        print(f"[Tenders] Reminder job error: {exc}")


@app.route("/api/match-crew", methods=["POST"])
@require_operator
def api_match_crew():
    d = request.get_json()
    # Gather employee history from Supabase
    profiles = {}
    if supabase_client:
        checkins = supabase_client.table("checkins").select("*").order("entry_date", desc=True).limit(200).execute().data or []
        reviews  = supabase_client.table("reviews").select("*").execute().data or []
        review_map = {r["checkin_id"]: r for r in reviews}
        for c in checkins:
            name = c["worker_name"]
            if name not in profiles:
                profiles[name] = {"checkins": [], "trust_scores": [], "avg_scores": []}
            profiles[name]["checkins"].append(c)
            if c["avg_score"]:
                profiles[name]["avg_scores"].append(c["avg_score"])
            rv = review_map.get(c["id"])
            if rv:
                profiles[name]["trust_scores"].append(rv.get("accuracy_score", 7))

    summary = {}
    for name, p in profiles.items():
        avgs = p["avg_scores"]
        trust = p["trust_scores"]
        summary[name] = {
            "total_checkins": len(p["checkins"]),
            "avg_self_score": round(sum(avgs)/len(avgs), 1) if avgs else "N/A",
            "avg_trust_score": round(sum(trust)/len(trust), 1) if trust else "N/A",
            "recent_work": [c.get("work_description","")[:100] for c in p["checkins"][:3]],
        }

    prompt = f"""You are Lumia, the operations AI for Ashrah Painting in Winnipeg, Canada.

Job Details:
- Client: {d.get('client_name')}
- Site: {d.get('site_address')}
- Work: {d.get('work_description')}
- Start Date: {d.get('start_date') or 'TBD'}
- Painters Needed: {d.get('painters_needed', 2)}

Employee Profiles (based on check-in history and manager reviews):
{json.dumps(summary, indent=2)}

Based on this data, provide:
1. Which {d.get('painters_needed', 2)} employee(s) you recommend for this job and why
2. Estimated duration in days
3. Any special considerations or warnings

Be specific and reference the data. If trust scores are low, flag it."""

    try:
        client = _anthropic.Anthropic()
        response = client.messages.create(
            model=MODEL, max_tokens=1000,
            messages=[{"role": "user", "content": prompt}]
        )
        result = response.content[0].text
    except Exception as exc:
        result = f"AI error: {exc}"

    return jsonify({"result": result})


@app.route("/api/save-job", methods=["POST"])
@require_operator
def api_save_job():
    d = request.get_json()
    assigned = d.get("assigned_employees") or []
    if isinstance(assigned, str):
        assigned = [assigned] if assigned else []
    # Deduplicate while preserving order
    seen: set[str] = set()
    assigned = [n for n in assigned if not (n in seen or seen.add(n))]
    _status = (d.get("status") or "awarded").strip().lower().replace(" ", "_")
    if _status not in ("awarded", "active", "on_hold", "completed", "invoiced", "closed"):
        _status = "awarded"
    job_info = {
        "client_name":        d.get("client_name"),
        "site_address":       d.get("site_address"),
        "work_description":   d.get("work_description"),
        "start_date":         d.get("start_date") or None,
        "painters_needed":    int(d.get("painters_needed", 2)),
        "status":             _status,
        "assigned_employees": assigned,
        "po_number":          (d.get("po_number") or "").strip() or None,
        "planned_completion_date": d.get("planned_completion_date") or None,
    }
    # Optional scope metrics + estimated hours (added 2026-04 — calibration loop)
    raw_metrics = d.get("scope_metrics")
    if raw_metrics:
        try:
            scope_obj = raw_metrics if isinstance(raw_metrics, dict) else json.loads(raw_metrics)
            job_info["scope_metrics"] = scope_obj
        except Exception:
            pass
    try:
        eh = float(d.get("estimated_hours") or 0)
        if eh > 0:
            job_info["estimated_hours"] = eh
    except (TypeError, ValueError):
        pass
    new_job_id = None
    if supabase_client:
        try:
            ins = supabase_client.table("jobs").insert(job_info).execute()
            if ins.data: new_job_id = ins.data[0].get("id")
        except Exception as exc:
            # Fallback: drop the new columns if the schema migration hasn't run yet
            print(f"[Jobs] Insert failed ({exc}) — retrying without optional columns")
            for k in ("scope_metrics", "estimated_hours", "po_number", "planned_completion_date"):
                job_info.pop(k, None)
            ins = supabase_client.table("jobs").insert(job_info).execute()
            if ins.data: new_job_id = ins.data[0].get("id")

    def _send_all():
        _notify_assigned_employees(job_info, assigned)
        client_notified = _notify_client_of_assignment(job_info, assigned)
        _log_assignment(job_info, assigned, client_notified)

    if assigned:
        threading.Thread(target=_send_all, daemon=True).start()
    # Always fire the kickoff notice — independent of crew assignment.
    threading.Thread(target=lambda: _notify_kickoff_specialist(job_info, new_job_id), daemon=True).start()

    msg = f"Job saved! Crew ({', '.join(assigned)}) notified. Client email sent." if assigned else "Job saved (no employees assigned)."
    sp = _get_kickoff_specialist()
    if sp: msg += f" Kickoff request emailed to {sp.get('name')}."
    return jsonify({"message": msg})


@app.route("/api/assign-employees", methods=["POST"])
@require_operator
def api_assign_employees():
    d = request.get_json()
    job_id       = d.get("job_id")
    assigned     = d.get("assigned_employees") or []
    notify_client = d.get("notify_client", True)   # pass False for silent assignment
    seen: set[str] = set()
    assigned = [n for n in assigned if not (n in seen or seen.add(n))]
    if not supabase_client or not job_id:
        return jsonify({"ok": False, "error": "Missing data"})
    supabase_client.table("jobs").update({"assigned_employees": assigned}).eq("id", job_id).execute()
    job_row = (supabase_client.table("jobs").select("*").eq("id", job_id).execute().data or [None])[0]
    emailed = []
    client_notified = False
    if assigned and job_row:
        emailed = _notify_assigned_employees(job_row, assigned)
        if notify_client:
            client_notified = _notify_client_of_assignment(job_row, assigned)
        _log_assignment(job_row, assigned, client_notified)
    return jsonify({"ok": True, "emailed": emailed, "client_notified": client_notified, "silent": not notify_client})


