@app.route("/api/report-schedule", methods=["GET"])
@require_role("owner")
def api_get_report_schedule():
    """Return the current auto-send time."""
    hour, minute = 18, 0
    if supabase_client:
        try:
            row = supabase_client.table("settings").select("value") \
                .eq("key", "report_schedule_time").execute().data
            if row:
                hour, minute = map(int, row[0]["value"].split(":"))
        except Exception:
            pass
    return jsonify({"ok": True, "time": f"{hour:02d}:{minute:02d}"})


@app.route("/api/report-schedule", methods=["POST"])
@require_role("owner")
def api_set_report_schedule():
    """Update the auto-send time and reschedule the job."""
    d = request.get_json()
    time_str = (d.get("time") or "").strip()
    try:
        hour, minute = map(int, time_str.split(":"))
        assert 0 <= hour <= 23 and 0 <= minute <= 59
    except Exception:
        return jsonify({"ok": False, "message": "Invalid time format. Use HH:MM."})

    # Persist to Supabase settings table
    if supabase_client:
        try:
            existing = supabase_client.table("settings").select("id") \
                .eq("key", "report_schedule_time").execute().data
            if existing:
                supabase_client.table("settings").update({"value": time_str}) \
                    .eq("key", "report_schedule_time").execute()
            else:
                supabase_client.table("settings").insert(
                    {"key": "report_schedule_time", "value": time_str}
                ).execute()
        except Exception as exc:
            print(f"[Schedule] Could not save to DB: {exc}")

    # Reschedule the APScheduler job. Only the worker holding the scheduler
    # lock has a live _scheduler; on other workers it's None. The setting is
    # already saved to the DB above, and the new time takes effect on the next
    # restart/redeploy regardless.
    if globals().get("_scheduler") is not None:
        try:
            _scheduler.reschedule_job(
                "daily_reports", trigger="cron", hour=hour, minute=minute,
            )
            print(f"[Scheduler] Rescheduled daily reports to {hour:02d}:{minute:02d} Winnipeg time")
        except Exception as exc:
            return jsonify({"ok": True, "message": f"Saved to {time_str}. (Scheduler note: {exc})"})

    return jsonify({"ok": True, "message": f"Auto-send updated to {time_str} Winnipeg time."})


def _run_daily_reports() -> None:
    """Aggregate today's check-ins by site/client and send one consolidated report per client."""
    today = date.today().isoformat()
    print(f"[Scheduler] Running daily reports for {today}")
    if not supabase_client:
        print("[Scheduler] Supabase not configured — skipping")
        return
    try:
        checkins = supabase_client.table("checkins").select("*").eq("entry_date", today).execute().data or []
        # Also pull from Supabase clients table
        db_clients = supabase_client.table("clients").select("*").execute().data or []
    except Exception as exc:
        print(f"[Scheduler] Error fetching data: {exc}")
        return

    # Build combined client lookup: hardcoded CLIENTS + DB clients
    all_clients: dict[str, dict] = dict(CLIENTS)
    for c in db_clients:
        kw = (c.get("site_keyword") or "").lower().strip()
        if kw:
            # Parse recipients — supports new multi-recipient column + old email_2 fallback
            recs = c.get("recipients") or []
            if isinstance(recs, str):
                try: recs = json.loads(recs)
                except Exception: recs = []
            if not recs:
                recs = [{"name": "", "email": c["client_email"]}]
                if c.get("client_email_2"):
                    recs.append({"name": "", "email": c["client_email_2"]})
            all_clients[kw] = {
                "client_name":  c["client_name"],
                "client_email": c["client_email"],
                "recipients":   recs,
            }

    # Build a name → client info map so we can resolve via the job's client_name
    # (this is the new path for multi-site clients who don't have a site_keyword).
    name_index: dict[str, dict] = {}
    for c in db_clients:
        nm = (c.get("client_name") or "").strip().lower()
        if not nm: continue
        recs = c.get("recipients") or []
        if isinstance(recs, str):
            try: recs = json.loads(recs)
            except Exception: recs = []
        if not recs:
            recs = [{"name": "", "email": c["client_email"]}]
            if c.get("client_email_2"):
                recs.append({"name": "", "email": c["client_email_2"]})
        name_index[nm] = {
            "client_name":  c["client_name"],
            "client_email": c["client_email"],
            "recipients":   recs,
        }

    # Look up jobs by id so we can route check-ins via job → client_name
    today_job_ids = {(ci.get("job_id") or "").strip() for ci in checkins if (ci.get("job_id") or "").strip()}
    jobs_by_id: dict[str, dict] = {}
    if today_job_ids:
        try:
            jrows = supabase_client.table("jobs").select("id,client_name,site_address") \
                .in_("id", list(today_job_ids)).execute().data or []
            for j in jrows: jobs_by_id[str(j.get("id"))] = j
        except Exception: pass

    # Group check-ins. Resolution priority:
    #   1. If the check-in has a job_id → look up the job's client_name → use that client
    #   2. Otherwise fall back to site_keyword matching (legacy path)
    client_checkins: dict[str, list] = {}
    for ci in checkins:
        site_addr = ci.get("site_address") or ""
        info = None; keyword = ""
        # Path 1: job → client_name
        jid = (ci.get("job_id") or "").strip()
        if jid and jid in jobs_by_id:
            jclient = (jobs_by_id[jid].get("client_name") or "").strip().lower()
            if jclient and jclient in name_index:
                info = name_index[jclient]
                keyword = jclient  # use the name as the dedup key for this run
        # Path 2: site_keyword match against the legacy all_clients dict
        if info is None:
            for kw, ci_info in all_clients.items():
                if _site_match(kw, site_addr):
                    info = ci_info; keyword = kw; break
        if info is None:
            continue
        key = info["client_email"]
        client_checkins.setdefault(key, {"info": info, "keyword": keyword, "entries": []})
        client_checkins[key]["entries"].append(ci)

    if not client_checkins:
        print(f"[Scheduler] No client check-ins found for {today}")
        return

    tracker = WorkforceTracker()
    reporter = DailyReportSender(
        client=_anthropic.Anthropic(),
        smtp_host=ZOHO_SMTP_HOST,
        smtp_port=ZOHO_SMTP_PORT,
        user=ZOHO_EMAIL,
        password=ZOHO_PASSWORD,
        from_email=ZOHO_EMAIL,
    )

    for email_key, bucket in client_checkins.items():
        info    = bucket["info"]
        keyword = bucket.get("keyword", "")
        entries = bucket["entries"]
        crew    = [e["worker_name"] for e in entries]
        for name in crew:
            tracker.add_worker(Worker(worker_id=name, name=name))
        work_completed = "\n\n".join(
            f"{e['worker_name']}: {e.get('work_description','')}" for e in entries if e.get("work_description")
        )
        plans = [e.get("tomorrows_plan","") for e in entries if e.get("tomorrows_plan")]
        dr = DailyReport(
            report_date=today,
            job_id="",
            site_address=(entries[0].get("site_address") or ""),
            client_name=info["client_name"],
            client_email=info["client_email"],
            crew_present=crew,
            work_completed=work_completed,
            work_planned=" | ".join(plans),
            issues="",
            overall_status="On Schedule",
        )
        try:
            import httpx as _httpx
            resend_key = os.getenv("RESEND_API_KEY", "")
            content = reporter.generate(dr, tracker)
            _augment_report_with_ask_lumia(content, keyword, dr.client_name, dr.client_email)
            subject   = content.get("subject", f"Daily Site Report — {dr.site_address} — {today}")
            html_body = content.get("html_body", "")
            plain_body = content.get("plain_body", "")
            # Append photo grid
            all_photo_urls = []
            for e in entries:
                for u in (e.get("photo_urls") or "").split(","):
                    u = u.strip()
                    if u:
                        all_photo_urls.append(u)
            if all_photo_urls:
                photo_grid = _build_photo_grid_html(all_photo_urls)
                html_body = html_body.rstrip()
                if html_body.endswith("</body></html>"):
                    html_body = html_body[:-14] + photo_grid + "</body></html>"
                else:
                    html_body += photo_grid
            recs_list = info.get("recipients") or [{"name":"","email": dr.client_email}]
            recipients = list({r["email"] for r in recs_list if r.get("email")})
            cc_list = [OWNER_EMAIL] if OWNER_EMAIL and OWNER_EMAIL not in recipients else []
            if resend_key:
                resp = _httpx.post(
                    "https://api.resend.com/emails",
                    headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
                    json={"from": "Ashrah Painting <noreply@ashrah.ai>", "to": recipients,
                          "cc": cc_list,
                          "subject": subject, "html": html_body, "text": plain_body},
                    timeout=15,
                )
                sent = resp.status_code in (200, 201)
                if sent:
                    try:
                        supabase_client.table("sent_reports").insert({
                            "client_name":  dr.client_name,
                            "client_email": dr.client_email,
                            "site_address": dr.site_address,
                            "subject":      subject,
                            "plain_body":   plain_body,
                            "html_body":    html_body,
                        }).execute()
                    except Exception:
                        pass
            else:
                sent = False
            print(f"[Scheduler] Report {'sent' if sent else 'FAILED'} → {dr.client_email}")
        except Exception as exc:
            print(f"[Scheduler] Report error for {dr.client_email}: {exc}")


# ---------------------------------------------------------------------------
# NIGHTLY CLIENT-ESCALATION DIGEST — emails Ahmad unresolved client questions
# ---------------------------------------------------------------------------
def _run_client_escalation_digest() -> None:
    if not supabase_client or not OWNER_EMAIL:
        return
    try:
        rows = supabase_client.table("client_escalations") \
            .select("id,client_id,question,assistant_response,created_at") \
            .is_("resolved_at", "null") \
            .is_("notified_at", "null") \
            .order("created_at").execute().data or []
    except Exception as exc:
        print(f"[Digest] fetch error: {exc}")
        return
    if not rows:
        return

    client_ids = list({r["client_id"] for r in rows if r.get("client_id")})
    name_by_id: dict[str, str] = {}
    try:
        crows = supabase_client.table("clients").select("id,client_name,client_email") \
            .in_("id", client_ids).execute().data or []
        name_by_id = {c["id"]: f"{c.get('client_name','')} ({c.get('client_email','')})" for c in crows}
    except Exception:
        pass

    blocks = []
    for r in rows:
        who = name_by_id.get(r.get("client_id"), "Client")
        blocks.append(
            f"<p><b>{who}</b> &mdash; <span style='color:#666'>{r.get('created_at','')}</span><br>"
            f"<b>Q:</b> {r.get('question','')}<br>"
            f"<b>Lumia reply:</b> {r.get('assistant_response','')}</p>"
        )
    html = "<h2>Lumia — pending client follow-ups</h2>" + "\n".join(blocks)
    plain = "\n\n".join(
        f"{name_by_id.get(r.get('client_id'),'Client')} ({r.get('created_at','')})\n"
        f"Q: {r.get('question','')}\nLumia reply: {r.get('assistant_response','')}"
        for r in rows
    )

    try:
        import httpx as _httpx
        resend_key = os.getenv("RESEND_API_KEY", "")
        if not resend_key:
            print("[Digest] No RESEND_API_KEY — skipping email")
            return
        resp = _httpx.post(
            "https://api.resend.com/emails",
            headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
            json={
                "from":    "Lumia — Ashrah Painting <noreply@ashrah.ai>",
                "to":      [OWNER_EMAIL],
                "subject": f"Lumia: {len(rows)} client question(s) waiting on you",
                "html":    html,
                "text":    plain,
            },
            timeout=15,
        )
        if resp.status_code in (200, 201):
            now = datetime.utcnow().isoformat()
            for r in rows:
                try:
                    supabase_client.table("client_escalations") \
                        .update({"notified_at": now}).eq("id", r["id"]).execute()
                except Exception:
                    pass
            print(f"[Digest] Sent {len(rows)} escalation(s) to {OWNER_EMAIL}")
        else:
            print(f"[Digest] Email failed: {resp.status_code} {resp.text}")
    except Exception as exc:
        print(f"[Digest] send error: {exc}")



ZOHO_IMAP_HOST     = os.getenv("ZOHO_IMAP_HOST", "imap.zoho.com")
ZOHO_IMAP_PORT     = int(os.getenv("ZOHO_IMAP_PORT", "993"))
# Fall back to existing Zoho SMTP creds when IMAP-specific ones aren't set.
# Strip whitespace (stray newlines often sneak in when pasting into Railway).
ZOHO_IMAP_USER     = (os.getenv("ZOHO_IMAP_USER", "")     or os.getenv("ZOHO_EMAIL", "")).strip()
ZOHO_IMAP_PASSWORD = (os.getenv("ZOHO_IMAP_PASSWORD", "") or os.getenv("ZOHO_PASSWORD", "")).strip()


def _scan_zoho_for_tenders(include_read: bool = False, days_back: int = 14) -> int:
    """Poll Zoho IMAP for emails that look like tender invitations.

    - `include_read=False` (default, used by auto-poll): only UNSEEN messages.
    - `include_read=True` (manual "Scan Email Now" button): every message in
      the window, read or not. Lets the user re-scan after they've already
      opened a bid email in Zoho.

    Dedup is handled at insert time (we skip rows whose name+close_date already
    exist in the tenders table), so re-scanning is safe."""
    if not ZOHO_IMAP_USER or not ZOHO_IMAP_PASSWORD:
        return 0
    import imaplib, email
    from email.header import decode_header

    added = 0
    try:
        mail = imaplib.IMAP4_SSL(ZOHO_IMAP_HOST, ZOHO_IMAP_PORT)
        mail.login(ZOHO_IMAP_USER, ZOHO_IMAP_PASSWORD)
        mail.select("INBOX")
        # Only unread messages from the last 14 days to keep it fast
        from datetime import timedelta as _td
        since = (date.today() - _td(days=days_back)).strftime("%d-%b-%Y")
        search_q = f'(SINCE "{since}")' if include_read else f'(UNSEEN SINCE "{since}")'
        typ, data = mail.search(None, search_q)
        if typ != "OK":
            mail.logout()
            return 0
        uids = data[0].split() if data and data[0] else []
        print(f"[Zoho IMAP] {len(uids)} unread message(s) to scan")

        for uid in uids:
            typ, msg_data = mail.fetch(uid, "(BODY.PEEK[])")  # PEEK = don't mark seen yet
            if typ != "OK" or not msg_data or not msg_data[0]:
                continue
            raw = msg_data[0][1]
            msg = email.message_from_bytes(raw)

            def _hdr(h):
                v = msg.get(h, "")
                parts = decode_header(v)
                out = ""
                for txt, enc in parts:
                    if isinstance(txt, bytes):
                        try: out += txt.decode(enc or "utf-8", errors="replace")
                        except Exception: out += txt.decode("utf-8", errors="replace")
                    else:
                        out += txt
                return out.strip()

            subject = _hdr("Subject")
            from_   = _hdr("From")
            import re as _re
            m = _re.search(r"[\w.+-]+@[\w.-]+\.\w+", from_)
            sender_email = m.group(0) if m else from_
            sender_name  = from_.split("<")[0].strip().strip('"') or sender_email

            # Get the plain text body
            body_text = ""
            if msg.is_multipart():
                for part in msg.walk():
                    ctype = part.get_content_type()
                    disp  = str(part.get("Content-Disposition") or "")
                    if ctype == "text/plain" and "attachment" not in disp:
                        try:
                            body_text = part.get_payload(decode=True).decode(
                                part.get_content_charset() or "utf-8", errors="replace")
                            break
                        except Exception:
                            pass
                if not body_text:
                    for part in msg.walk():
                        if part.get_content_type() == "text/html":
                            try:
                                html = part.get_payload(decode=True).decode(
                                    part.get_content_charset() or "utf-8", errors="replace")
                                body_text = _re.sub(r'<[^>]+>', ' ', html)
                                break
                            except Exception:
                                pass
            else:
                try:
                    body_text = msg.get_payload(decode=True).decode(
                        msg.get_content_charset() or "utf-8", errors="replace")
                except Exception:
                    body_text = msg.get_payload() or ""

            if not _looks_like_tender_email(subject, body_text):
                # Leave it as UNSEEN so the user still reads it in Zoho.
                continue

            print(f"[Zoho IMAP] Tender candidate: '{subject}' from {sender_email}")
            result = _ingest_tender_email(subject, body_text, sender_name, sender_email)
            if result.get("ok"):
                added += 1
                # Notify Ahmad in Lumia (no reply to sender)
                _send_tender_confirmation_email(result["tender"], sender_email, subject)
                # Mark as read so we don't re-process next poll
                try:
                    mail.store(uid, "+FLAGS", "\\Seen")
                except Exception:
                    pass

        mail.logout()
    except Exception as exc:
        print(f"[Zoho IMAP] Error: {exc}")
    return added



# ---------------------------------------------------------------------------
# SMS — Twilio texting (crew reminders + client texts)
# ---------------------------------------------------------------------------
def _normalize_phone(p: str) -> str:
    """Normalize to E.164. Canadian/US default. Returns '' if not usable."""
    if not p:
        return ""
    p = p.strip()
    if p.startswith("+"):
        digits = "+" + re.sub(r"\D", "", p[1:])
        return digits if len(digits) >= 11 else ""
    digits = re.sub(r"\D", "", p)
    if len(digits) == 10:
        return "+1" + digits
    if len(digits) == 11 and digits.startswith("1"):
        return "+" + digits
    return ""


def _sms_contact_name(phone_e164: str) -> str:
    """Resolve a phone number to a known crew member or client name."""
    if not supabase_client or not phone_e164:
        return ""
    try:
        emps = supabase_client.table("employees").select("name,phone").execute().data or []
        for e in emps:
            if _normalize_phone(e.get("phone") or "") == phone_e164:
                return e.get("name") or ""
    except Exception:
        pass
    try:
        cls = supabase_client.table("clients").select("client_name,client_phone,portal_phone").execute().data or []
        for c in cls:
            for k in ("client_phone", "portal_phone"):
                if _normalize_phone(c.get(k) or "") == phone_e164:
                    return c.get("client_name") or ""
    except Exception:
        pass
    return ""


def _log_sms(direction: str, phone: str, body: str, *, category: str = "sms",
             contact_name: str = "") -> None:
    """Record a text (in or out) in the sms_messages table for the Texts tab.
    Best-effort — never blocks a send."""
    if not supabase_client:
        return
    try:
        supabase_client.table("sms_messages").insert({
            "direction":    direction,           # 'out' | 'in'
            "phone":        phone,                # the OTHER party (for threading)
            "body":         body[:1600],
            "category":     category,
            "contact_name": contact_name or _sms_contact_name(phone),
            "created_at":   datetime.utcnow().isoformat(),
        }).execute()
    except Exception as exc:
        print(f"[SMS] log skipped ({direction}): {exc}")


def _send_sms(to_number: str, body: str, *, category: str = "sms") -> tuple[bool, str]:
    """Send one SMS via Twilio. Returns (ok, detail). Gated on Twilio env vars —
    no-ops cleanly if not configured. Every send is logged to the Mailbox."""
    sid      = os.getenv("TWILIO_ACCOUNT_SID", "")
    token    = os.getenv("TWILIO_AUTH_TOKEN", "")
    from_num = os.getenv("TWILIO_PHONE_NUMBER", "")
    if not (sid and token and from_num):
        return False, "Twilio not configured (set TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_PHONE_NUMBER)"
    to_e164 = _normalize_phone(to_number)
    if not to_e164:
        return False, f"Invalid phone number: {to_number!r}"
    import httpx
    try:
        r = httpx.post(
            f"https://api.twilio.com/2010-04-01/Accounts/{sid}/Messages.json",
            auth=(sid, token),
            data={"From": from_num, "To": to_e164, "Body": body[:1500]},
            timeout=15.0,
        )
        ok = r.status_code in (200, 201)
        try:
            _log_outbox(category=category, to=[to_e164], subject="SMS",
                        body_text=body, status="sent" if ok else "error",
                        error=None if ok else r.text[:200])
        except Exception:
            pass
        if ok:
            _log_sms("out", to_e164, body, category=category)
        if not ok:
            print(f"[SMS] Twilio {r.status_code}: {r.text[:200]}")
            return False, f"Twilio {r.status_code}: {r.text[:160]}"
        return True, "sent"
    except Exception as exc:
        print(f"[SMS] send failed: {exc}")
        return False, str(exc)


def _active_employees_with_phones() -> list[dict]:
    """Active employees that have a usable phone number."""
    if not supabase_client:
        return []
    try:
        rows = supabase_client.table("employees").select("name,phone,active") \
            .eq("active", True).execute().data or []
    except Exception:
        # phone column may not exist yet
        return []
    out = []
    for r in rows:
        ph = _normalize_phone(r.get("phone") or "")
        if ph:
            out.append({"name": r.get("name"), "phone": ph})
    return out


def _send_crew_morning_reminder():
    """~7:00 AM — remind crew to review today's plan."""
    crew = _active_employees_with_phones()
    sent = 0
    for c in crew:
        ok, _ = _send_sms(c["phone"],
            f"Good morning {c['name'].split()[0] if c.get('name') else ''} — review today's plan in Lumia before you start. lumia.ashrah.ai",
            category="sms_morning")
        sent += 1 if ok else 0
    print(f"[SMS] Morning reminder sent to {sent}/{len(crew)} crew")


def _send_crew_evening_reminder():
    """~4:30 PM — remind crew who haven't submitted today's report yet."""
    if not supabase_client:
        return
    crew = _active_employees_with_phones()
    today = date.today().isoformat()
    try:
        cks = supabase_client.table("checkins").select("worker_name").eq("entry_date", today).execute().data or []
    except Exception:
        cks = []
    submitted = {(c.get("worker_name") or "").strip().lower() for c in cks}
    sent = 0
    for c in crew:
        if (c.get("name") or "").strip().lower() in submitted:
            continue   # already submitted — don't nag
        ok, _ = _send_sms(c["phone"],
            f"Hi {c['name'].split()[0] if c.get('name') else ''} — don't forget to submit your daily report in Lumia before you head home. lumia.ashrah.ai",
            category="sms_evening")
        sent += 1 if ok else 0
    print(f"[SMS] Evening reminder sent to {sent} crew (skipped those already submitted)")


def _send_arrival_nudges():
    """~9:30 AM — nudge crew assigned to open jobs who haven't logged arrival."""
    if not supabase_client:
        return
    crew = {c["name"].strip().lower(): c for c in _active_employees_with_phones() if c.get("name")}
    if not crew:
        return
    today = date.today().isoformat()
    start_of_day = today + "T00:00:00"
    # Who has already logged arrival today?
    try:
        arr = supabase_client.table("arrivals").select("worker_name") \
            .gte("arrived_at", start_of_day).execute().data or []
    except Exception:
        arr = []
    arrived = {(a.get("worker_name") or "").strip().lower() for a in arr}
    # Who's assigned to open jobs?
    try:
        jobs = supabase_client.table("jobs").select("assigned_employees,status") \
            .in_("status", WORKING_JOB_STATUSES).execute().data or []
    except Exception:
        jobs = []
    assigned = set()
    for j in jobs:
        for emp in (j.get("assigned_employees") or []):
            assigned.add((emp or "").strip().lower())
    sent = 0
    for name_lc in assigned:
        if name_lc in arrived:
            continue
        c = crew.get(name_lc)
        if not c:
            continue
        ok, _ = _send_sms(c["phone"],
            f"Hi {c['name'].split()[0] if c.get('name') else ''} — tap 'I've Arrived On Site' in Lumia when you get to the job. lumia.ashrah.ai",
            category="sms_arrival")
        sent += 1 if ok else 0
    print(f"[SMS] Arrival nudge sent to {sent} crew")


@app.route("/api/sms/send", methods=["POST"])
@require_operator
def api_sms_send():
    """Manually text a crew member or client from the dashboard."""
    d = request.get_json(silent=True) or {}
    to   = (d.get("to") or "").strip()
    body = (d.get("body") or "").strip()
    if not to or not body:
        return jsonify({"ok": False, "error": "Need a phone number and a message"}), 400
    ok, detail = _send_sms(to, body, category="sms_manual")
    return jsonify({"ok": ok, "detail": detail})


@app.route("/api/sms/incoming", methods=["POST"])
def api_sms_incoming():
    """Twilio inbound webhook — fires when someone texts the Lumia number.
    Public (Twilio posts here). Logs the reply so it shows in the Texts tab.
    Set this URL in Twilio → your number → Messaging → 'A message comes in'."""
    # Twilio posts form-encoded: From, To, Body
    frm  = (request.form.get("From") or "").strip()
    body = (request.form.get("Body") or "").strip()
    if frm and body:
        phone = _normalize_phone(frm) or frm
        _log_sms("in", phone, body, category="sms_inbound")
        print(f"[SMS] Inbound from {phone}: {body[:80]}")
    # Empty TwiML response = received, no auto-reply
    return ("<?xml version='1.0' encoding='UTF-8'?><Response></Response>",
            200, {"Content-Type": "text/xml"})


@app.route("/api/sms/threads")
@require_operator
def api_sms_threads():
    """Return recent texts grouped into conversations by phone number."""
    if not supabase_client:
        return jsonify({"ok": True, "threads": []})
    try:
        rows = supabase_client.table("sms_messages").select("*") \
            .order("created_at", desc=True).limit(500).execute().data or []
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 200
    threads: dict[str, dict] = {}
    for m in rows:
        ph = m.get("phone") or "?"
        if ph not in threads:
            threads[ph] = {
                "phone":        ph,
                "contact_name": m.get("contact_name") or "",
                "messages":     [],
                "last_at":      m.get("created_at"),
            }
        threads[ph]["messages"].append({
            "direction":  m.get("direction"),
            "body":       m.get("body"),
            "created_at": m.get("created_at"),
            "category":   m.get("category"),
        })
        if not threads[ph]["contact_name"] and m.get("contact_name"):
            threads[ph]["contact_name"] = m.get("contact_name")
    # messages currently newest-first per thread; reverse to chronological
    out = []
    for t in threads.values():
        t["messages"].reverse()
        out.append(t)
    out.sort(key=lambda t: t.get("last_at") or "", reverse=True)
    return jsonify({"ok": True, "threads": out})


@app.route("/api/employee/phone", methods=["POST"])
@require_role("owner")
def api_set_employee_phone():
    """Set/update an employee's phone number + language preference (for SMS)."""
    if not supabase_client:
        return jsonify({"ok": False, "error": "No database"}), 500
    d = request.get_json(silent=True) or {}
    emp_id = d.get("id")
    if not emp_id:
        return jsonify({"ok": False, "error": "Employee id required"}), 400
    patch = {}
    if "phone" in d:
        patch["phone"] = (d.get("phone") or "").strip()
    if "language" in d:
        lang = (d.get("language") or "en").lower()
        patch["language"] = lang if lang in ("en", "ar", "fr") else "en"
    if not patch:
        return jsonify({"ok": False, "error": "Nothing to update"}), 400
    try:
        supabase_client.table("employees").update(patch).eq("id", emp_id).execute()
        return jsonify({"ok": True, "normalized": _normalize_phone(patch.get("phone", ""))})
    except Exception as exc:
        msg = str(exc)
        if "phone" in msg or "language" in msg or "column" in msg.lower():
            return jsonify({"ok": False, "error":
                "Run in Supabase first: alter table employees add column if not exists phone text, add column if not exists language text default 'en';"}), 400
        return jsonify({"ok": False, "error": msg}), 500


# ---------------------------------------------------------------------------
# BACKGROUND SCHEDULER — end-of-day client reports at 18:00 Winnipeg time
# ---------------------------------------------------------------------------
# CRITICAL: with multiple Gunicorn workers, APScheduler would start in EVERY
# worker — firing every scheduled email N times (this caused the triple-email
# bug). We guard it with a single-instance lock: only the first worker that
# can bind a local lock socket starts the scheduler. The others skip it.
def _acquire_scheduler_lock() -> bool:
    """Returns True for exactly ONE process on this host. Uses an abstract-ish
    TCP bind on a fixed localhost port as a cross-worker mutex."""
    import socket as _sock
    try:
        s = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
        s.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 0)
        s.bind(("127.0.0.1", 47655))   # arbitrary lock port
        s.listen(1)
        # Stash on the module so the socket isn't garbage-collected (which
        # would release the lock).
        globals()["_SCHEDULER_LOCK_SOCKET"] = s
        return True
    except OSError:
        return False   # another worker already holds the lock


if _acquire_scheduler_lock():
    try:
        _scheduler = BackgroundScheduler(timezone="America/Winnipeg")
        _scheduler.add_job(_run_daily_reports, "cron", hour=18, minute=0,
                           id="daily_reports", replace_existing=True)
        _scheduler.add_job(_run_client_escalation_digest, "cron", hour=20, minute=0,
                           id="client_escalation_digest", replace_existing=True)
        _scheduler.add_job(_send_tender_reminders, "cron", hour=8, minute=0,
                           id="tender_reminders", replace_existing=True)
        _scheduler.add_job(_scan_zoho_for_tenders, "interval", minutes=15,
                           id="zoho_tender_scan", replace_existing=True)
        _scheduler.add_job(_send_attention_digest, "cron", hour=7, minute=0,
                           id="attention_digest", replace_existing=True)
        # SMS crew reminders (no-op cleanly if Twilio env vars aren't set)
        _scheduler.add_job(_send_crew_morning_reminder, "cron", hour=7, minute=0,
                           id="sms_morning", replace_existing=True)
        _scheduler.add_job(_send_arrival_nudges, "cron", hour=9, minute=30,
                           id="sms_arrival", replace_existing=True)
        _scheduler.add_job(_send_crew_evening_reminder, "cron", hour=16, minute=30,
                           id="sms_evening", replace_existing=True)
        # Crew Chat: learn each employee's communication style nightly (Haiku, cheap)
        _scheduler.add_job(_learn_employee_profiles, "cron", hour=3, minute=15,
                           id="crew_learn_profiles", replace_existing=True)
        _scheduler.start()
        print("[Scheduler] STARTED in this worker — daily reports 18:00, escalations 20:00, "
              "tender reminders 08:00, attention digest 07:00, Zoho scan every 15 min (Winnipeg)")
    except Exception as _sched_exc:
        print(f"[Scheduler] Could not start scheduler: {_sched_exc}")
else:
    _scheduler = None
    print("[Scheduler] Skipped in this worker (another worker holds the scheduler lock) — "
          "prevents duplicate scheduled emails.")


# ---------------------------------------------------------------------------
# INBOUND EMAIL WEBHOOK — lumia@ashrah.ai replies automatically
# ---------------------------------------------------------------------------
_TENDER_KEYWORDS = (
    "invitation to bid", "invitation to tender", "request for proposal", "request for quotation",
    "request for tender", " rfp ", " rfq ", " itb ", " itt ",
    "tender invitation", "bid invitation", "tender opportunity", "bid opportunity",
    "submission deadline", "closing date", "tender closing", "bid closing",
    "proposal deadline", "tender package",
)

def _looks_like_tender_email(subject: str, body: str) -> bool:
    blob = " " + (subject + " " + body).lower() + " "
    return any(kw in blob for kw in _TENDER_KEYWORDS)


def _normalize_tender_name(name: str) -> str:
    """Strip addendum/itemized/RFP noise so variants of the same project collapse
    to the same key (e.g. 'U of M CL3 … - Addendum' == 'U of Manitoba CL3 …')."""
    n = (name or "").lower()
    junk = ["addendum", "itemized", "revised", "revision", "re-issue", "reissue",
            "re issue", "update", "nda only", "ndas only", "nda", "final",
            "invitation to bid", "invitation to tender", "rfp", "rfq", "itb", "itt",
            "eoi", "tender", "bid", "painting", "paint", "renovation", "reno",
            "2024", "2025", "2026", "2027", "2028"]
    for j in junk:
        n = n.replace(j, " ")
    # 'u of manitoba' -> 'u of m' so both forms match
    n = n.replace("university of manitoba", "u of m").replace("u of manitoba", "u of m")
    n = re.sub(r"[^a-z0-9 ]", " ", n)
    n = re.sub(r"\s+", " ", n).strip()
    return n


def _find_matching_tender(name: str):
    """Return an existing tender row if `name` is the same project (fuzzy).
    Prevents addenda / itemized follow-ups from creating duplicate tenders."""
    import difflib
    if not supabase_client:
        return None
    norm_new = _normalize_tender_name(name)
    if not norm_new or len(norm_new) < 4:
        return None
    try:
        rows = supabase_client.table("tenders").select("id,name,close_date,status").limit(500).execute().data or []
    except Exception:
        return None
    set_new = set(norm_new.split())
    best, best_score = None, 0.0
    for r in rows:
        norm_ex = _normalize_tender_name(r.get("name"))
        if not norm_ex:
            continue
        ratio = difflib.SequenceMatcher(None, norm_new, norm_ex).ratio()
        set_ex = set(norm_ex.split())
        overlap = len(set_new & set_ex) / max(1, min(len(set_new), len(set_ex)))
        score = max(ratio, overlap)
        if score > best_score:
            best_score, best = score, r
    return best if best and best_score >= 0.7 else None


def _ingest_tender_email(subject: str, body: str, sender_name: str, sender_email: str) -> dict:
    """Use Claude to pull {name, client, close_date, description} from a bid email
    and insert into the tenders table."""
    if not supabase_client:
        return {"ok": False, "error": "Database not connected."}

    today = date.today().isoformat()
    prompt = f"""You are extracting structured tender data from an email inviting Ashrah Painting to bid.

Today's date: {today}

EMAIL:
From: {sender_name} <{sender_email}>
Subject: {subject}
Body:
{body[:6000]}

Extract this JSON ONLY (no markdown, no commentary):
{{
  "name": "short project name (e.g. 'Pembina Trails SD Painting RFP 2026')",
  "client": "issuer / company name (or null if not stated)",
  "close_date": "YYYY-MM-DD format. Pick the SUBMISSION deadline (when bids close). If the email mentions a time, ignore time and use the calendar date only. If no date is found, use null.",
  "description": "one or two short sentences describing the scope of work being tendered"
}}

Rules:
- close_date MUST be in the future. If only a relative term like 'in two weeks' is given, compute from today.
- If the email is not actually a tender invitation, return {{"name": null}}.
- Return ONLY the JSON object, nothing else."""

    try:
        ai_client = _anthropic.Anthropic()
        resp = ai_client.messages.create(
            model=MODEL,
            max_tokens=600,
            messages=[{"role": "user", "content": prompt}],
        )
        text = resp.content[0].text.strip()
        if text.startswith("```"):
            text = text.split("\n", 1)[1].rsplit("```", 1)[0]
        obj = json.loads(text)
    except Exception as exc:
        print(f"[Tender Ingest] AI error: {exc}")
        return {"ok": False, "error": f"AI extraction failed: {exc}"}

    name       = (obj.get("name") or "").strip()
    close_date = (obj.get("close_date") or "").strip()
    if not name or not close_date or close_date == "null":
        return {"ok": False, "error": "Could not extract tender info."}

    # One tender per project — fuzzy-match against existing tenders so addenda /
    # itemized / re-issued emails update the SAME tender instead of duplicating.
    try:
        match = _find_matching_tender(name)
        if match:
            upd = {}
            # An addendum often extends the deadline — keep the latest close_date
            if close_date and close_date > (match.get("close_date") or ""):
                upd["close_date"] = close_date
            if upd:
                supabase_client.table("tenders").update(upd).eq("id", match["id"]).execute()
            print(f"[Tender Ingest] '{name}' matches existing project '{match.get('name')}' — updated, not duplicated")
            return {"ok": False, "error": "Already tracked (same project)."}
    except Exception as exc:
        print(f"[Tender Ingest] match check failed: {exc}")

    try:
        row = {
            "name":        name,
            "client":      (obj.get("client") or "").strip() or None,
            "description": (obj.get("description") or "").strip() or None,
            "close_date":  close_date,
            "status":      "open",
            "notes":       f"Auto-ingested from email by Lumia. Sender: {sender_email}",
        }
        ins = supabase_client.table("tenders").insert(row).execute()
        saved = (ins.data or [row])[0]
        print(f"[Tender Ingest] Added '{name}' closes {close_date}")
        return {"ok": True, "tender": saved}
    except Exception as exc:
        print(f"[Tender Ingest] DB insert error: {exc}")
        return {"ok": False, "error": str(exc)}


def _send_tender_confirmation_email(tender: dict, original_sender: str, original_subject: str) -> None:
    """Notify Ahmad that a tender was auto-added."""
    if not OWNER_EMAIL:
        return
    import httpx as _httpx
    resend_key = os.getenv("RESEND_API_KEY", "")
    if not resend_key:
        return
    body = (
        f"Hi Ahmad,\n\n"
        f"I added a tender to your queue based on an email from {original_sender}.\n\n"
        f"Tender:  {tender.get('name')}\n"
        f"Client:  {tender.get('client') or '—'}\n"
        f"Close:   {tender.get('close_date')}\n"
        f"Source subject: {original_subject}\n\n"
        f"You will get a reminder 2 days before the close date.\n"
        f"Open the Tenders tab in Lumia to review or edit.\n\n"
        f"— Lumia\n"
        f"Automated response — Lumia, Ashrah Painting operations system."
    )
    try:
        subject_t = f"📥 Tender added — {tender.get('name')}"
        _httpx.post(
            "https://api.resend.com/emails",
            headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
            json={"from":"Lumia <noreply@ashrah.ai>","to":[OWNER_EMAIL],
                  "subject": subject_t,
                  "text": body},
            timeout=15,
        )
        try:
            _log_outbox(category="tender_alert", to=[OWNER_EMAIL],
                        subject=subject_t, body_text=body,
                        related_kind="tender", related_id=str(tender.get("id") or ""))
        except Exception: pass
    except Exception as exc:
        print(f"[Tender Ingest] Confirmation email error: {exc}")


@app.route("/webhook/inbound-email", methods=["POST"])
def webhook_inbound_email():
    """Resend forwards inbound emails here. Lumia reads, thinks, and replies."""
    import httpx as _httpx

    try:
        data = request.get_json(force=True) or {}
    except Exception:
        data = {}

    sender      = data.get("from", "")
    sender_name = data.get("from_name", sender.split("<")[0].strip())
    subject     = data.get("subject", "")
    body_text   = data.get("text", "") or data.get("plain", "") or ""
    body_html   = data.get("html", "")

    # Strip HTML if only html available
    if not body_text and body_html:
        import re
        body_text = re.sub(r'<[^>]+>', ' ', body_html).strip()

    # Extract sender email
    import re as _re
    email_match = _re.search(r'[\w.+-]+@[\w.-]+\.\w+', sender)
    reply_to = email_match.group(0) if email_match else sender

    if not reply_to:
        return jsonify({"ok": False, "message": "No sender address"}), 200

    # Don't reply to ourselves or bounce loops
    if "noreply" in reply_to.lower() or "no-reply" in reply_to.lower():
        return jsonify({"ok": True, "message": "Ignored no-reply sender"}), 200

    print(f"[Inbound] Email from {reply_to} | Subject: {subject}")

    # ── Tender invitation detection ──────────────────────────────────────────
    # If this email looks like a bid invitation, extract close date + add to
    # the tenders queue instead of running the normal reply flow.
    if _looks_like_tender_email(subject, body_text):
        result = _ingest_tender_email(subject, body_text, sender_name, reply_to)
        if result.get("ok"):
            # Confirmation to Ahmad — short, factual, signed by Lumia
            _send_tender_confirmation_email(result["tender"], reply_to, subject)
        return jsonify({"ok": True, "ingested_as_tender": result.get("ok", False),
                        "tender": result.get("tender")}), 200

    # ── Build context from Supabase ──────────────────────────────────────────
    context_parts = []
    if supabase_client:
        try:
            checkins = supabase_client.table("checkins").select("*") \
                .order("entry_date", desc=True).limit(60).execute().data or []
            if checkins:
                rows = [
                    f"  [{c['entry_date']}] {c['worker_name']} @ {c['site_address']} | "
                    f"avg={c.get('avg_score','?')}/10 | {(c.get('work_description') or '')[:100]}"
                    for c in checkins
                ]
                context_parts.append("RECENT CHECK-INS:\n" + "\n".join(rows))
        except Exception:
            pass
        try:
            jobs = supabase_client.table("jobs").select("*") \
                .order("created_at", desc=True).limit(20).execute().data or []
            if jobs:
                rows = [
                    f"  [{j.get('status','?').upper()}] {j.get('client_name','?')} @ {j.get('site_address','?')} | "
                    f"crew: {', '.join(j.get('assigned_employees') or [])} | start: {j.get('start_date','TBD')}"
                    for j in jobs
                ]
                context_parts.append("JOBS:\n" + "\n".join(rows))
        except Exception:
            pass
        try:
            clients = supabase_client.table("clients").select("*").execute().data or []
            if clients:
                rows = [f"  {c.get('client_name')} | {c.get('client_email')} | keyword: {c.get('site_keyword')}" for c in clients]
                context_parts.append("CLIENTS:\n" + "\n".join(rows))
        except Exception:
            pass

    data_context = "\n\n".join(context_parts) if context_parts else "(no data available)"
    today = date.today().isoformat()

    system_prompt = f"""You are Lumia, the operations assistant for Ashrah Painting in Winnipeg, Canada — owned by Ahmad Ashrah (CEO).

You are replying to an email sent to lumia@ashrah.ai. You have access to live company data below — use it to give specific, accurate answers.

Today's date: {today}

--- LIVE COMPANY DATA ---
{data_context}
--- END DATA ---

WRITING RULES:
- Write like a professional person, not a template. Direct and clear.
- BANNED phrases — never use: "I hope this email finds you well", "Please don't hesitate to reach out", "Going forward", "It was a pleasure", "I wanted to touch base", "At your earliest convenience", "Thank you for your continued support", or any filler language.
- Short answers. Say what needs to be said, nothing extra.
- Never invent facts. If you don't know, say: "Contact Ahmad directly at ahmad@ashrahpainting.ca."
- Sign off as: Lumia | Ashrah Painting | info@ashrahpainting.ca
- Add one final line: "Automated response — Lumia, Ashrah Painting operations system."
- Plain text only, no markdown."""

    try:
        ai_client = _anthropic.Anthropic()
        resp = ai_client.messages.create(
            model=MODEL,
            max_tokens=600,
            system=system_prompt,
            messages=[{
                "role": "user",
                "content": f"Email from {sender_name} ({reply_to}):\nSubject: {subject}\n\n{body_text}"
            }]
        )
        reply_body = resp.content[0].text.strip()
    except Exception as exc:
        print(f"[Inbound] AI error: {exc}")
        return jsonify({"ok": False}), 200

    # Send the reply
    resend_key = os.getenv("RESEND_API_KEY", "")
    if not resend_key:
        print("[Inbound] No RESEND_API_KEY — cannot reply")
        return jsonify({"ok": False}), 200

    reply_subject = subject if subject.lower().startswith("re:") else f"Re: {subject}"
    reply_html = "<p>" + reply_body.replace("\n\n", "</p><p>").replace("\n", "<br>") + "</p>"

    try:
        cc = [OWNER_EMAIL] if OWNER_EMAIL and OWNER_EMAIL != reply_to else []
        r = _httpx.post(
            "https://api.resend.com/emails",
            headers={"Authorization": f"Bearer {resend_key}", "Content-Type": "application/json"},
            json={
                "from":    "Lumia — Ashrah Painting <noreply@ashrah.ai>",
                "to":      [reply_to],
                "cc":      cc,
                "subject": reply_subject,
                "html":    reply_html,
                "text":    reply_body,
            },
            timeout=20,
        )
        print(f"[Inbound] Reply {'sent' if r.status_code in (200,201) else 'FAILED'} → {reply_to}")
    except Exception as exc:
        print(f"[Inbound] Reply error: {exc}")

    return jsonify({"ok": True}), 200


